import { useNavigate, useLocation } from "react-router-dom";
import CreateRecipeWizard from "@/components/community/recipe/CreateRecipeWizard";

const CreateRecipePage = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const prefillFromAI = (location.state as any)?.prefillFromAI || null;

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <CreateRecipeWizard
        onClose={() => navigate("/community/create")}
        onSuccess={() => navigate("/community")}
        prefillFromAI={prefillFromAI}
      />
    </div>
  );
};

export default CreateRecipePage;
